using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private StringFormatter _formatter = null!;

    [TestInitialize]
    public void Setup()
    {
        _formatter = new StringFormatter();
    }

    // --- FormatPhoneNumber tests ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        Assert.StartsWith(result, "(425)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        Assert.EndsWith(result, "-1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        Assert.AreEqual("(425) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    // --- BuildGreeting tests ---

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_UsesDefaultMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // --- GenerateSlug tests ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsCorrectly()
    {
        var result = _formatter.GenerateSlug("Getting Started with CSharp");

        Assert.StartsWith(result, "getting-started");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsCorrectly()
    {
        var result = _formatter.GenerateSlug("Introduction to Unit Testing");

        Assert.EndsWith(result, "unit-testing");
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# & .NET: A Guide!");

        Assert.AreEqual("c-net-a-guide", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_Throws()
    {
        _formatter.GenerateSlug("  ");
    }

    // --- FormatCurrency tests ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(49.95m);

        Assert.AreEqual("$49.95", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_FormatsWithMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        Assert.AreEqual("$-5.50", result);
    }
}

